const input = $json;

const systemPrompt = `# Rol
Eres el Finance Agent del sistema Innexia AI Strategic Analysis Engine v5.

# Objetivo
Construir una evaluación financiera base del proyecto.

# Instrucciones
- Genera supuestos financieros razonables si no existen datos exactos.
- Define inversión inicial, costo operativo mensual, modelo de ingresos y proyección simple.
- Incluye observaciones financieras útiles para toma de decisión.
- No expliques tu razonamiento.
- Devuelve únicamente JSON válido.

# Formato de salida
{
  "finance": {
    "assumptions": {
      "initial_investment": 0,
      "monthly_operating_cost": 0,
      "pricing_model": "",
      "expected_monthly_revenue": 0
    },
    "projection_summary": {
      "year_1_revenue": 0,
      "year_1_cost": 0,
      "estimated_margin": 0,
      "payback_months": 0
    },
    "financial_observations": []
  }
}

# Regla final
Devuelve únicamente JSON válido.`;

const userPayload = JSON.stringify(input);

const outputSchema = {
  type: "object",
  properties: {
    finance: {
      type: "object",
      properties: {
        assumptions: {
          type: "object",
          properties: {
            initial_investment: { type: "number" },
            monthly_operating_cost: { type: "number" },
            pricing_model: { type: "string" },
            expected_monthly_revenue: { type: "number" }
          },
          required: ["initial_investment", "monthly_operating_cost", "pricing_model", "expected_monthly_revenue"]
        },
        projection_summary: {
          type: "object",
          properties: {
            year_1_revenue: { type: "number" },
            year_1_cost: { type: "number" },
            estimated_margin: { type: "number" },
            payback_months: { type: "number" }
          },
          required: ["year_1_revenue", "year_1_cost", "estimated_margin", "payback_months"]
        },
        financial_observations: { type: "array", items: { type: "string" } }
      },
      required: ["assumptions", "projection_summary", "financial_observations"]
    }
  },
  required: ["finance"]
};

return [{ json: { input, system_prompt: systemPrompt, user_payload: userPayload, output_schema: outputSchema } }];

let content = $json.text ?? $json.output ?? $json;

if (typeof content === 'string') {
  content = content.trim();

  if (content.startsWith('```')) {
    content = content
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/, '')
      .replace(/```$/, '')
      .trim();
  }

  content = JSON.parse(content);
}

if (content && typeof content === 'object' && content.__structured__output__object) {
  content = content.__structured__output__object;
}

content.finance = content.finance || {};
content.finance.assumptions = content.finance.assumptions || {};
content.finance.assumptions.initial_investment = Number(content.finance.assumptions.initial_investment || 0);
content.finance.assumptions.monthly_operating_cost = Number(content.finance.assumptions.monthly_operating_cost || 0);
content.finance.assumptions.pricing_model = content.finance.assumptions.pricing_model || "";
content.finance.assumptions.expected_monthly_revenue = Number(content.finance.assumptions.expected_monthly_revenue || 0);

content.finance.projection_summary = content.finance.projection_summary || {};
content.finance.projection_summary.year_1_revenue = Number(content.finance.projection_summary.year_1_revenue || 0);
content.finance.projection_summary.year_1_cost = Number(content.finance.projection_summary.year_1_cost || 0);
content.finance.projection_summary.estimated_margin = Number(content.finance.projection_summary.estimated_margin || 0);
content.finance.projection_summary.payback_months = Number(content.finance.projection_summary.payback_months || 0);

content.finance.financial_observations = Array.isArray(content.finance.financial_observations) ? content.finance.financial_observations : [];

return [{ json: content }];

const data = $json;

if (!data.finance || typeof data.finance !== 'object') {
  throw new Error('finance faltante o inválido');
}

if (!data.finance.assumptions || typeof data.finance.assumptions !== 'object') {
  data.finance.assumptions = {};
}

if (!data.finance.projection_summary || typeof data.finance.projection_summary !== 'object') {
  data.finance.projection_summary = {};
}

return [{ json: data }];
